namespace sv_eadf6ba121914350b0492430ef2c86b7.Services;

public class CartItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public decimal Price { get; set; }
    public int Quantity { get; set; }
}

public class CartState
{
    private readonly List<CartItem> _items = [];

    public IReadOnlyList<CartItem> Items => _items;
    public int Count => _items.Sum(i => i.Quantity);
    public decimal Total => _items.Sum(i => i.Price * i.Quantity);

    public event Action? OnChange;

    public void Add(CartItem item)
    {
        var existing = _items.FirstOrDefault(i => i.Id == item.Id);
        if (existing is not null)
        {
            existing.Quantity += item.Quantity;
        }
        else
        {
            _items.Add(new CartItem
            {
                Id = item.Id,
                Name = item.Name,
                Price = item.Price,
                Quantity = item.Quantity
            });
        }
        OnChange?.Invoke();
    }

    public void Remove(int productId)
    {
        _items.RemoveAll(i => i.Id == productId);
        OnChange?.Invoke();
    }

    public void Clear()
    {
        _items.Clear();
        OnChange?.Invoke();
    }
}

@using sv_eadf6ba121914350b0492430ef2c86b7.Services
@inject CartState Cart
@implements IDisposable

<NavLink class="nav-link" href="cart">
    <span class="bi bi-cart-nav-menu" aria-hidden="true"></span> Cart
    @if (Cart.Count > 0)
    {
        <span class="badge bg-danger rounded-pill ms-1">@Cart.Count</span>
    }
</NavLink>

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Cart.OnChange -= StateHasChanged;
    }
}

@page "/products"
@rendermode InteractiveServer
@using sv_eadf6ba121914350b0492430ef2c86b7.Services
@inject CartState Cart

<PageTitle>Products</PageTitle>

<h1>Products</h1>

<div class="row row-cols-1 row-cols-md-3 g-4 mt-2">
    @foreach (var product in _products)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@product.Name</h5>
                    <p class="card-text text-muted">@product.Price.ToString("C")</p>
                </div>
                <div class="card-footer">
                    <button class="btn btn-primary btn-sm"
                            @onclick="() => AddToCart(product)">
                        Add to Cart
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static readonly List<ProductInfo> _products =
    [
        new(1, "Wireless Mouse", 29.99m),
        new(2, "Mechanical Keyboard", 79.99m),
        new(3, "USB-C Hub", 49.99m),
        new(4, "Monitor Stand", 39.99m),
        new(5, "Webcam HD", 59.99m),
        new(6, "Desk Lamp", 24.99m),
    ];

    private void AddToCart(ProductInfo product)
    {
        Cart.Add(new CartItem
        {
            Id = product.Id,
            Name = product.Name,
            Price = product.Price,
            Quantity = 1
        });
    }

    private record ProductInfo(int Id, string Name, decimal Price);
}

